# -- 3. REAL-TIME SPECTRUM ANALYZER --
class MusicSpectrumAnalyzer:
    """FFT-based spectrum analyzer with music recognition.
    Processes the physics audio signal and extracts:
    - Frequency spectrum (magnitude in dB)
    - Detected notes with confidence
    - Chord identification
    - Spectral features (centroid, rolloff, flux)
    - Octave band energies
    """
    def __init__(self, sample_rate=44100, fft_size=4096):
        self.sr = sample_rate
        self.fft_size = fft_size
        self.freq_resolution = sample_rate / fft_size  # Hz per bin
        self.nyquist = sample_rate / 2.0
        # Pre-compute Hann window
        self.window = 0.5 * (1.0 - np.cos(2.0 * np.pi * np.arange(fft_size) / fft_size))
        # Pre-compute frequency axis
        self.freq_axis = np.fft.rfftfreq(fft_size, 1.0 / sample_rate)
        self.n_bins = len(self.freq_axis)
        # Results (updated each analysis frame)
        self.magnitude_db = np.full(self.n_bins, -120.0)  # dB spectrum
        self.magnitude_linear = np.zeros(self.n_bins)
        self.detected_notes = []     # [(note_name, octave, freq, amplitude_db, cents_off)]
        self.detected_chord = ''     # e.g. 'Cmaj7'
        self.detected_key = ''       # e.g. 'C major'
        self.spectral_centroid = 0.0 # Hz
        self.spectral_rolloff = 0.0  # Hz (95% energy cutoff)
        self.spectral_flux = 0.0     # change between frames
        self.rms_db = -120.0         # overall loudness
        self.octave_bands = np.zeros(10)  # energy in octave bands 0-9
        self.peak_freq = 0.0         # dominant frequency
        self.peak_note = ''          # dominant note name
        self._prev_magnitude = np.zeros(self.n_bins)
        self.consonance = 0.0        # Sethares dissonance measure (inverted)
        self.overtone_strengths = np.zeros(16)  # strength of first 16 harmonics
        self.pitch_class_energy = np.zeros(12)  # chroma vector (energy per pitch class)

    def analyze(self, signal):
        """Run full spectrum analysis on a signal chunk (numpy array, mono)."""
        if signal is None or len(signal) < self.fft_size:
            return
        # Take a chunk from the middle of the signal for stability
        mid = len(signal) // 2
        start = max(0, mid - self.fft_size // 2)
        chunk = signal[start:start + self.fft_size].astype(np.float64)
        if len(chunk) < self.fft_size:
            chunk = np.pad(chunk, (0, self.fft_size - len(chunk)))
        # Apply Hann window
        windowed = chunk * self.window
        # FFT
        fft_result = np.fft.rfft(windowed)
        self.magnitude_linear = np.abs(fft_result) / self.fft_size
        # Convert to dB (with floor at -120 dB)
        self.magnitude_db = 20.0 * np.log10(self.magnitude_linear + 1e-12)
        self.magnitude_db = np.maximum(self.magnitude_db, -120.0)
        # RMS level
        rms = math.sqrt(np.mean(chunk ** 2) + 1e-30)
        self.rms_db = 20.0 * math.log10(rms + 1e-12)
        # Spectral centroid: weighted average frequency
        mag_sum = np.sum(self.magnitude_linear) + 1e-30
        self.spectral_centroid = float(np.sum(self.freq_axis * self.magnitude_linear) / mag_sum)
        # Spectral rolloff: frequency below which 95% of energy is contained
        cumulative = np.cumsum(self.magnitude_linear ** 2)
        total_energy = cumulative[-1] + 1e-30
        rolloff_idx = np.searchsorted(cumulative, 0.95 * total_energy)
        self.spectral_rolloff = float(self.freq_axis[min(rolloff_idx, self.n_bins - 1)])
        # Spectral flux: L2 change from previous frame
        diff = self.magnitude_linear - self._prev_magnitude
        self.spectral_flux = float(np.sqrt(np.mean(diff ** 2)))
        self._prev_magnitude = self.magnitude_linear.copy()
        # Peak frequency
        peak_idx = np.argmax(self.magnitude_linear[1:]) + 1  # skip DC
        self.peak_freq = float(self.freq_axis[peak_idx])
        name, oct, cents = _freq_to_note_name(self.peak_freq)
        self.peak_note = f"{name}{oct}" if self.peak_freq > 20 else "---"
        # Octave band energies (C0~16Hz to C9~8372Hz)
        for band in range(10):
            f_lo = _midi_to_freq(band * 12 + 12)   # C of that octave
            f_hi = _midi_to_freq((band + 1) * 12 + 12)
            idx_lo = max(1, int(f_lo / self.freq_resolution))
            idx_hi = min(self.n_bins - 1, int(f_hi / self.freq_resolution))
            if idx_hi > idx_lo:
                self.octave_bands[band] = float(np.mean(self.magnitude_linear[idx_lo:idx_hi] ** 2))
            else:
                self.octave_bands[band] = 0.0
        # Pitch class chroma vector (energy in each of 12 semitones, summed across octaves)
        self.pitch_class_energy[:] = 0.0
        for oct in range(1, 9):
            for pc in range(12):
                midi = (oct + 1) * 12 + pc
                f_center = _midi_to_freq(midi)
                # Bin range: +/- half semitone
                f_lo = f_center * (2 ** (-0.5 / 12))
                f_hi = f_center * (2 ** (0.5 / 12))
                idx_lo = max(1, int(f_lo / self.freq_resolution))
                idx_hi = min(self.n_bins - 1, int(f_hi / self.freq_resolution) + 1)
                if idx_hi > idx_lo:
                    self.pitch_class_energy[pc] += float(np.sum(self.magnitude_linear[idx_lo:idx_hi] ** 2))
        # Detect notes: find peaks in spectrum above threshold
        self._detect_notes()
        # Detect chord from detected notes
        self._detect_chord()
        # Compute consonance (Sethares model)
        self._compute_consonance()
        # Overtone analysis relative to fundamental
        self._analyze_overtones()

    def _detect_notes(self):
        """Find spectral peaks and map to musical notes."""
        self.detected_notes = []
        if self.rms_db < -60:
            return
        # Simple peak detection: local maxima above threshold
        threshold_db = self.rms_db + 6.0  # peaks must be 6dB above RMS
        threshold_db = max(threshold_db, -50.0)
        mag = self.magnitude_db
        peaks = []
        for i in range(2, self.n_bins - 2):
            if (mag[i] > threshold_db and
                mag[i] > mag[i-1] and mag[i] > mag[i+1] and
                mag[i] > mag[i-2] and mag[i] > mag[i+2]):
                freq = float(self.freq_axis[i])
                if 20 <= freq <= 12000:
                    peaks.append((freq, float(mag[i])))
        # Sort by amplitude, keep top 12 peaks
        peaks.sort(key=lambda x: -x[1])
        peaks = peaks[:12]
        for freq, amp_db in peaks:
            name, octave, cents = _freq_to_note_name(freq)
            self.detected_notes.append((name, octave, freq, amp_db, cents))

    def _detect_chord(self):
        """Identify chord from detected notes using pitch class matching."""
        self.detected_chord = ''
        if len(self.detected_notes) < 2:
            return
        # Get unique pitch classes present (by amplitude)
        pc_set = set()
        for name, octave, freq, amp_db, cents in self.detected_notes[:6]:
            pc = _MT_NOTE_NAMES.index(name)
            pc_set.add(pc)
        if len(pc_set) < 2:
            return
        # Try every root + chord type, score by coverage
        best_score = 0
        best_chord = ''
        for root_pc in range(12):
            for chord_name, intervals in MUSIC_MATH['chords'].items():
                chord_pcs = set((root_pc + iv) % 12 for iv in intervals)
                # Score = how many chord tones are present / total chord tones
                match = len(chord_pcs & pc_set)
                score = match / len(chord_pcs) if chord_pcs else 0
                # Bonus if all chord tones found and no extra notes
                if match == len(chord_pcs):
                    score += 0.3
                if score > best_score:
                    best_score = score
                    best_chord = f"{_MT_NOTE_NAMES[root_pc]}{chord_name}"
        if best_score >= 0.6:
            self.detected_chord = best_chord

    def _compute_consonance(self):
        """Sethares dissonance model: pairwise partial interactions."""
        if len(self.detected_notes) < 2:
            self.consonance = 1.0
            return
        # Plomp-Levelt curve: d(f1,f2) = exp(-a*s) - exp(-b*s)
        # where s = |f2-f1| / (0.24 * min(f1,f2) + 0.021 * (f1+f2)/2)
        a, b = 3.5, 5.75
        total_dissonance = 0.0
        n_pairs = 0
        freqs = [f for _, _, f, _, _ in self.detected_notes[:8]]
        for i in range(len(freqs)):
            for j in range(i + 1, len(freqs)):
                f1, f2 = min(freqs[i], freqs[j]), max(freqs[i], freqs[j])
                if f1 < 20:
                    continue
                s = (f2 - f1) / (0.24 * f1 + 0.021 * (f1 + f2) / 2.0 + 1e-10)
                d = math.exp(-a * s) - math.exp(-b * s)
                total_dissonance += max(0, d)
                n_pairs += 1
        if n_pairs > 0:
            avg_d = total_dissonance / n_pairs
            self.consonance = max(0.0, min(1.0, 1.0 - avg_d * 4.0))
        else:
            self.consonance = 1.0

    def _analyze_overtones(self):
        """Measure strength of first 16 harmonics relative to fundamental."""
        self.overtone_strengths[:] = 0.0
        if self.peak_freq < 20:
            return
        f0 = self.peak_freq
        for n in range(1, 17):
            fn = f0 * n
            if fn > self.nyquist:
                break
            bin_idx = int(fn / self.freq_resolution)
            if 0 < bin_idx < self.n_bins:
                # Take max in small neighborhood to handle frequency smearing
                lo = max(1, bin_idx - 2)
                hi = min(self.n_bins, bin_idx + 3)
                self.overtone_strengths[n - 1] = float(np.max(self.magnitude_linear[lo:hi]))

    def get_summary(self):
        """Return a compact dict summary for AI observer consumption."""
        return {
            'peak_freq': self.peak_freq,
            'peak_note': self.peak_note,
            'rms_db': self.rms_db,
            'spectral_centroid': self.spectral_centroid,
            'spectral_rolloff': self.spectral_rolloff,
            'spectral_flux': self.spectral_flux,
            'consonance': self.consonance,
            'detected_notes': [(n, o, round(f, 1), round(a, 1), round(c, 1))
                               for n, o, f, a, c in self.detected_notes[:6]],
            'detected_chord': self.detected_chord,
            'pitch_class_energy': self.pitch_class_energy.tolist(),
            'octave_bands': self.octave_bands.tolist(),
            'overtone_strengths': self.overtone_strengths[:8].tolist(),
        }


# Global spectrum analyzer instance
_music_spectrum = MusicSpectrumAnalyzer(sample_rate=44100, fft_size=4096)
_spectrum_last_signal = None  # cached raw signal for visualization
