# == Neural Language Composer == No scripted sentences. ==
# Words are selected by hashing the observer's qualia vector, personality,
# and perceived state. Each observer's unique neural weights produce unique
# internal activations, so no two observers compose the same sentence.

def _nlc_pick(pool, *vals):
    """Deterministic pick from pool using neural activation hash."""
    h = 7
    for v in vals:
        _fv = abs(float(v)) if math.isfinite(float(v)) else 0.0
        h = ((h * 31) + int(min(_fv, 1e15) * 97531)) & 0x7FFFFFFF
    return pool[h % len(pool)]

def _nlc_pick_n(pool, n, *vals):
    """Pick n unique items from pool using neural hash spread."""
    results = []
    for i in range(n):
        h = 13 + i * 17
        for v in vals:
            _fv = abs(float(v)) if math.isfinite(float(v)) else 0.0
            h = ((h * 37 + i * 53) + int(min(_fv, 1e15) * 71993)) & 0x7FFFFFFF
        item = pool[h % len(pool)]
        if item not in results:
            results.append(item)
    return results

