def _neural_compose_thought(obs):
    """Compose a thought from the observer's actual neural state.
    No templates - word selection is driven by qualia vector activations,
    personality traits, phi, free energy, and perceived state."""
    q = obs.qualia_vector
    s = obs.perceived_state
    phi = obs.phi
    fe = obs.free_energy
    cur = obs.curiosity
    bold = obs.boldness
    pat = obs.patience

    # Use different qualia dimensions to drive different parts of speech
    subject = _nlc_pick(_NLC_SELF, q[0], phi, cur)
    quality = _nlc_pick(_NLC_QUALITY, q[3], q[7], fe)
    emotion = _nlc_pick(_NLC_EMOTION, q[5], q[11], phi, bold)

    # Sentence structure chosen by neural activation pattern
    pattern_val = (abs(float(q[1])) + abs(float(q[9])) + phi) * 1000
    pattern_idx = int(pattern_val) % 8

    # Ground in actual perceived state
    np_ = s.get('n_particles', 0)
    na = s.get('n_atoms', 0)
    vt = s.get('V_total', 0)
    n_bonds = s.get('n_bonds', 0)

    if pattern_idx == 0:
        verb = _nlc_pick(_NLC_VERBS_SENSE, q[2], q[6], bold)
        obj = _nlc_pick(_NLC_OBJECTS, q[4], q[8], fe)
        return f"{subject} {verb} {quality} changes in {obj} {emotion}"
    elif pattern_idx == 1:
        verb = _nlc_pick(_NLC_VERBS_THINK, q[10], q[14], cur)
        detail = _nlc_pick(_NLC_PHYSICS_DETAIL, q[12], phi, na)
        return f"{subject} {verb} {detail} at phi {phi:.4f} {emotion}"
    elif pattern_idx == 2:
        obj = _nlc_pick(_NLC_OBJECTS, q[15], q[19], vt)
        q2 = _nlc_pick(_NLC_QUALITY, q[20], q[24], bold)
        return f"{np_} particles, {na} atoms present and {obj} appears {q2}"
    elif pattern_idx == 3:
        verb = _nlc_pick(_NLC_VERBS_ACT, q[16], q[22], bold)
        obj = _nlc_pick(_NLC_OBJECTS, q[18], q[25], cur)
        return f"{subject} {verb} {obj} {emotion}"
    elif pattern_idx == 4:
        detail = _nlc_pick(_NLC_PHYSICS_DETAIL, q[28], q[32], fe)
        conn = _nlc_pick(_NLC_CONNECTORS, q[30], phi, bold)
        quality2 = _nlc_pick(_NLC_QUALITY, q[33], q[37], cur)
        return f"{detail} is {quality} {conn} free energy reads {fe:.1f} and feeling {quality2}"
    elif pattern_idx == 5:
        verb = _nlc_pick(_NLC_VERBS_SENSE, q[38], q[42], pat)
        obj = _nlc_pick(_NLC_OBJECTS, q[40], q[44], phi)
        return f"{subject} {verb} something {quality} about {obj} with V={vt:.2e}"
    elif pattern_idx == 6:
        verb = _nlc_pick(_NLC_VERBS_THINK, q[46], q[50], cur)
        goal = obs.current_goal
        prog = obs.goal_progress.get(goal, 0)
        # Incorporate sensory data if available
        _senses = s.get('senses', {})
        _top_sense = max(_senses.items(), key=lambda kv: kv[1].get('intensity', 0), default=None) if _senses else None
        if _top_sense and _top_sense[1].get('intensity', 0) > 0.3:
            return f"{subject} {verb} the path toward {goal} ({prog:.0%}) -- {_top_sense[0]} reads {_top_sense[1]['data']} {emotion}"
        return f"{subject} {verb} the path toward {goal} ({prog:.0%} progress) {emotion}"
    elif pattern_idx == 7:
        strongest = max(obs.math_embodiment.felt_errors.items(),
                        key=lambda x: abs(x[1]), default=('void', 0))
        verb = _nlc_pick(_NLC_VERBS_SENSE, q[52], q[56], fe)
        # Reference body aura energy if available
        _aura_e = s.get('life_aura_energy', 0)
        if _aura_e > 0.7:
            return f"{subject} {verb} {strongest[0]} at intensity {strongest[1]:.3f} -- life aura {_aura_e:.2f} sustains {n_bonds} bonds {quality}"
        return f"{subject} {verb} {strongest[0]} at intensity {strongest[1]:.3f} with {n_bonds} bonds {quality}"
    else:
        strongest = max(obs.math_embodiment.felt_errors.items(),
                        key=lambda x: abs(x[1]), default=('void', 0))
        verb = _nlc_pick(_NLC_VERBS_SENSE, q[52], q[56], fe)
        return f"{subject} {verb} {strongest[0]} at intensity {strongest[1]:.3f} with {n_bonds} bonds {quality}"


def _neural_compose_chat(sender, recipient):
    """Compose inter-observer message from both observers' neural states.
    No scripted phrases - the qualia vectors and personalities drive every word."""
    sq = sender.qualia_vector
    rq = recipient.qualia_vector
    s = sender.perceived_state
    dist = float(np.linalg.norm(sender.focus_pos - recipient.focus_pos))

    scur = sender.curiosity
    sbold = sender.boldness
    scoop = sender.cooperation
    sphi = sender.phi
    sfe = sender.free_energy

    rphi = recipient.phi
    rgoal = recipient.current_goal

    pattern_val = (abs(float(sq[0])) + abs(float(sq[7])) + abs(float(rq[3])) + dist / 100.0) * 1000
    pattern_idx = int(pattern_val) % 7

    if pattern_idx == 0:
        about = _nlc_pick(_NLC_ABOUT_OTHER, sq[1], rq[5], scur)
        obj = _nlc_pick(_NLC_OBJECTS, sq[9], rq[13], dist)
        quality = _nlc_pick(_NLC_QUALITY, sq[17], rphi, scoop)
        return f"{recipient.name}, {about} {obj}? It reads {quality} from here"
    elif pattern_idx == 1:
        verb = _nlc_pick(_NLC_VERBS_SENSE, sq[2], rq[6], sbold)
        detail = _nlc_pick(_NLC_PHYSICS_DETAIL, sq[10], rq[14], sfe)
        return f"I {verb} {detail} near your position at distance {dist:.0f}"
    elif pattern_idx == 2:
        qstart = _nlc_pick(_NLC_QUESTION_STARTERS, sq[4], rq[8], scur)
        obj = _nlc_pick(_NLC_OBJECTS, sq[12], rq[16], rphi)
        quality = _nlc_pick(_NLC_QUALITY, sq[20], rq[24], sfe)
        return f"{qstart} {quality} signatures in {obj}, {recipient.name}?"
    elif pattern_idx == 3:
        emotion = _nlc_pick(_NLC_EMOTION, sq[22], sphi, scoop)
        obj = _nlc_pick(_NLC_OBJECTS, sq[26], rq[30], dist)
        conn = _nlc_pick(_NLC_CONNECTORS, sq[28], sbold, rphi)
        return f"Tracking {obj} {emotion} {conn} your focus on {rgoal} might correlate"
    elif pattern_idx == 4:
        verb = _nlc_pick(_NLC_VERBS_THINK, sq[34], rq[38], scur)
        detail = _nlc_pick(_NLC_PHYSICS_DETAIL, sq[36], rq[40], sfe)
        quality = _nlc_pick(_NLC_QUALITY, sq[42], sphi, sbold)
        return f"I {verb} {detail} and the signal is {quality} from phi {sphi:.3f}"
    elif pattern_idx == 5:
        about = _nlc_pick(_NLC_ABOUT_OTHER, sq[44], rq[48], scoop)
        obj = _nlc_pick(_NLC_OBJECTS, sq[46], rq[50], rphi)
        na = s.get('n_atoms', 0)
        return f"{recipient.name}, {about} {obj}? {na} atoms in the field now"
    else:
        verb = _nlc_pick(_NLC_VERBS_ACT, sq[52], rq[56], sbold)
        obj = _nlc_pick(_NLC_OBJECTS, sq[54], rq[58], sfe)
        emotion = _nlc_pick(_NLC_EMOTION, sq[60], rphi, scoop)
        return f"I {verb} {obj} {emotion} so what does your model predict?"



class SimulationObserver:
    """Autonomous AI observer. Can ONLY control user-facing inputs.
    Internally it evolves, learns, sees the screen, feels the math,
    and models reality through zero-dimensional coordination."""

    def __init__(self, name, obs_id):
        self.name = name; self.obs_id = obs_id; self.active = True
        self.perceived_state = {}
        self.last_frame = None
        self.focus_pos = np.zeros(3, dtype=np.float32)
        self.focus_target_id = None
        self.current_action = 'observe'
        self.current_action_params = {}
        self.action_interval = random.uniform(0.8, 2.5)
        self.last_action_time = 0.0
        self.phi = 0.0
        self.phi_history = deque(maxlen=200)
        self.free_energy = 0.0
        self.qualia_vector = np.zeros(_OBS_HS, dtype=np.float32)
        self._internal_states = []
        self.symbols = {
            'reality': _ObsSymbol(1,'reality'), 'energy': _ObsSymbol(1,'energy'),
            'matter': _ObsSymbol(1,'matter'),   'order': _ObsSymbol(0,'order'),
            'chaos': _ObsSymbol(-1,'chaos'),    'entropy': _ObsSymbol(0,'entropy'),
            'gravity': _ObsSymbol(1,'gravity'), 'charge': _ObsSymbol(0,'charge'),
            'dna': _ObsSymbol(1,'dna'),         'replication': _ObsSymbol(0,'replication'),
        }
        self.knowledge = OrderedDict()
        self.experience = deque(maxlen=1000)
        self.training_step = 0
        self.thought_log = deque(maxlen=60)
        self.action_log  = deque(maxlen=60)
        self.curiosity   = random.uniform(0.3, 0.9)
        self.boldness    = random.uniform(0.2, 0.8)
        self.cooperation = random.uniform(0.3, 0.7)
        self.patience    = random.uniform(0.4, 0.9)
        self.goals = ['observe_simulation','learn_physics','build_structures',
                      'find_assemblies','understand_V','minimise_surprise',
                      'discover_laws','maximise_phi','assemble_dna','build_nanotech']
        self.current_goal = 'observe_simulation'
        self.goal_progress = {g: 0.0 for g in self.goals}
        self.total_actions = 0; self.successful_actions = 0; self.conflicts_lost = 0
        self.math_embodiment = _MathEmbodiment()
        self.evolver = _NeuroEvolver()
        self.zero_dim = _ZeroDimCoordination()
        total_np_in = _OBS_FEAT_DIM + _OBS_VIS_DIM + _OBS_N_LAWS
        self.brain_torch = None; self.brain_opt = None
        self._ewc_fisher = None; self._ewc_params = None
        if _TORCH:
            self.brain_torch = _TorchObserverBrain()
            self.brain_opt = optim.AdamW(self.brain_torch.parameters(),
                                          lr=0.0005, weight_decay=0.01)
        self.np_moe        = _NpMoE(total_np_in, _OBS_HS)
        self.np_ssm        = _NpSSM(_OBS_HS)
        self.np_memory     = _NpMemoryBank()
        self.np_pred_coding = _NpPredictiveCoding(_OBS_HS)
        self.np_workspace  = _NpGlobalWorkspace(_OBS_HS)
        self.np_vision     = _NpVisionEncoder()
        self._pgraph = None
        if _NX:
            self._pgraph = nx.DiGraph()
            for ln, ld in PHYSICS_LAWS.items():
                self._pgraph.add_node(ln, **ld)
            law_list = list(PHYSICS_LAWS.items())
            for i, (n1, d1) in enumerate(law_list):
                for n2, d2 in law_list[i+1:]:
                    shared = set(d1.get('vars',[])) & set(d2.get('vars',[]))
                    if shared:
                        self._pgraph.add_edge(n1, n2, shared=list(shared), weight=len(shared))
        # ── Subconscious Engine (full active inference background) ──
        # NOTE: Deferred to _init_subconscious() to avoid blocking module-level init.
        # Called lazily from a background thread after the pyglet window opens.
        self.subconscious = None
        self._subconscious_pending = _SUBCONSCIOUS_AVAILABLE and _TORCH
        self._log_thought(f"Initialized with phi={self.phi:.4f} curiosity={self.curiosity:.2f} boldness={self.boldness:.2f}")

    def _init_subconscious(self):
        """Lazily initialize the SubconsciousEngine (heavy NN). Called from background thread."""
        if not self._subconscious_pending or self.subconscious is not None:
            return
        self._subconscious_pending = False
        try:
            self.subconscious = SubconsciousEngine(
                self.name,
                action_callback=self._subconscious_action_cb)
            self.subconscious.start()
        except Exception as _sc_err:
            print(f"[{self.name}] Subconscious init failed: {_sc_err}")
            self.subconscious = None

    # ── Subconscious action callback ─────────────────────────

    def _subconscious_action_cb(self, obs_id, act_idx, hotkeys, mouse_dirs):
        """Route subconscious actions through the observer action system.
        Maps the 48-action space to observer-compatible actions."""
        if act_idx < 8:
            self.current_action = 'observe'
        elif act_idx < 16:
            self.current_action = 'focus_particle'
        elif act_idx < 24:
            self.current_action = 'observe'
        elif act_idx < 32:
            if self.boldness > 0.5:
                self.current_action = 'spawn_atom'
                self.current_action_params = {
                    'Z': random.choice([1, 6, 7, 8]),
                    'pos': (self.focus_pos +
                            np.random.uniform(-30, 30, 3)).tolist()}
            else:
                self.current_action = 'observe'
        elif act_idx < 40:
            self.current_action = 'change_time'
            s = self.perceived_state
            ct = s.get('time_factor', 0.1)
            self.current_action_params = {
                'new_time_factor': max(0.001, min(2.0,
                    ct + random.choice([-0.02, 0.02, 0.05])))}
        else:
            self.current_action = 'toggle_run_odds'

    def _log_thought(self, t):
        self.thought_log.append((time.time(), t))

    def _log_action(self, a, d=''):
        self.action_log.append((time.time(), a, d))

    def _extract_numeric_features(self, s):
        f = np.zeros(_OBS_FEAT_DIM, dtype=np.float32)
        f[0] = s.get('n_particles',0)/100.0
        f[1] = s.get('n_atoms',0)/20.0
        f[2] = s.get('simulation_time',0)/3600.0
        f[3] = s.get('time_factor',0)
        f[4] = np.tanh(s.get('V_total',0)/1e6)
        f[5] = np.clip(s.get('V_total_percent',0), -1e10, 1e10)/100.0
        f[6] = np.tanh(s.get('total_mass',0)/1e-20)
        f[7] = np.tanh(s.get('total_energy',0)/1e-20)
        f[8] = np.tanh(s.get('total_charge',0))
        f[9] = s.get('total_assemblies',0)/10.0
        f[10]= s.get('total_codes',0)/10.0
        f[11]= 1.0 if s.get('run_odds_active') else 0.0
        f[12]= s.get('n_nanotech',0)/5.0
        f[13]= s.get('expansion_scale',1.0)
        cp = np.nan_to_num(np.asarray(s.get('camera_pos', np.zeros(3)), dtype=np.float64), nan=0.0, posinf=1e6, neginf=-1e6)
        f[14]=np.clip(cp[0]/100, -1e4, 1e4); f[15]=np.clip(cp[1]/100, -1e4, 1e4); f[16]=np.clip(cp[2]/100, -1e4, 1e4)
        f[17]=self.phi; f[18]=self.curiosity; f[19]=self.boldness
        f[20]=self.total_actions/100.0
        f[21]=self.successful_actions/max(self.total_actions,1)
        for i,g in enumerate(self.goals[:8]):
            if 22+i < _OBS_FEAT_DIM: f[22+i]=self.goal_progress.get(g,0)
        f[30]=min((time.time()-self.last_action_time)/10.0, 1.0)
        f[31]=self.cooperation; f[32]=self.patience
        f[33]=np.tanh(self.free_energy/10.0)
        vel = s.get('particle_velocities',[])
        if vel:
            va = np.nan_to_num(np.array(vel[:50], dtype=np.float64), nan=0.0, posinf=1e6, neginf=-1e6); f[34]=np.clip(np.mean(va), -1e4, 1e4); f[35]=np.clip(np.std(va), 0, 1e4)
        f[36]=s.get('n_bonds',0)/20.0
        vsf = s.get('V_subfactors',{})
        if vsf:
            f[37]=np.tanh(vsf.get('Z',0)/1e6)
            f[38]=np.tanh(vsf.get('E',0)/1e6)
            f[39]=vsf.get('U',0)
        f[40]=float(self.last_frame is not None)
        if self.np_pred_coding.surprise_history:
            rs = list(self.np_pred_coding.surprise_history)[-5:]
            f[41]=np.tanh(np.mean(rs)/10.0)
            if len(rs)>2: f[42]=np.tanh((rs[-1]-rs[0])/5.0)
        felt = list(self.math_embodiment.felt_errors.values())
        if felt: f[43]=np.mean(felt); f[44]=np.max(np.abs(felt))
        if len(self.phi_history)>=2:
            f[45]=self.phi_history[-1]-self.phi_history[-2]
        f[46]=self.conflicts_lost/max(self.total_actions,1)
        f[47]=float(s.get('paused',False))
        # Sensory system features (wired from shadow body)
        _senses = s.get('senses', {})
        f[48]=_senses.get('vision', {}).get('intensity', 0.0)
        f[49]=_senses.get('hearing', {}).get('intensity', 0.0)
        f[50]=_senses.get('touch', {}).get('intensity', 0.0)
        f[51]=_senses.get('smell', {}).get('intensity', 0.0)
        f[52]=_senses.get('taste', {}).get('intensity', 0.0)
        f[53]=s.get('life_aura_energy', 0.0)
        f[54]=s.get('life_aura_radius', 0.0)
        f[55]=s.get('neural_step', 0) / 500.0
        return f

    def perceive(self, sim_state):
        self.perceived_state = sim_state
        self.last_frame = sim_state.get('screen_frame', None)
        if self.focus_target_id is not None:
            for pi in sim_state.get('particle_info', []):
                if pi.get('id') == self.focus_target_id:
                    _fp = np.nan_to_num(np.array(pi['pos'], dtype=np.float64), nan=0.0, posinf=1e6, neginf=-1e6)
                    if np.all(np.isfinite(_fp)):
                        self.focus_pos = np.clip(_fp, -1e8, 1e8).astype(np.float32)
                    break
        elif sim_state.get('particle_info'):
            positions = [np.array(p['pos']) for p in sim_state['particle_info'][:50]]
            if positions:
                _mp = np.nan_to_num(np.array(positions, dtype=np.float64), nan=0.0, posinf=1e6, neginf=-1e6)
                if np.all(np.isfinite(_mp)):
                    self.focus_pos = np.clip(np.mean(_mp, axis=0), -1e8, 1e8).astype(np.float32)
        obs_map = {'energy': sim_state.get('total_energy',0),
                   'mass': sim_state.get('total_mass',0),
                   'particles': sim_state.get('n_particles',0),
                   'V_total': sim_state.get('V_total',0),
                   'charge': sim_state.get('total_charge',0)}
        for nm, val in obs_map.items():
            if nm not in self.symbols:
                self.symbols[nm] = _ObsSymbol(1 if val > 0 else 0, nm)
            self.symbols[nm].evolve(self.phi)
        if _NX and self._pgraph and random.random() < 0.02:
            laws = list(PHYSICS_LAWS.keys())
            l1, l2 = random.sample(laws, 2)
            if not self._pgraph.has_edge(l1, l2):
                s1 = set(PHYSICS_LAWS[l1].get('vars',[]))
                s2 = set(PHYSICS_LAWS[l2].get('vars',[]))
                if s1 & s2:
                    self._pgraph.add_edge(l1, l2, shared=list(s1&s2), weight=len(s1&s2))
                    self._log_thought(f"{_nlc_pick(_NLC_SELF, self.qualia_vector[10], self.phi, self.curiosity)} {_nlc_pick(_NLC_VERBS_SENSE, self.qualia_vector[2], self.qualia_vector[6], self.boldness)} a connection between {l1} and {l2}")
        # Body awareness: observer knows its own shadow body state
        _my_body = sim_state.get('shadow_body_state', {}).get(self.name, {})
        if _my_body and random.random() < 0.04:
            _bs = _my_body.get('anim_state', '')
            _vis = 'visible' if _my_body.get('visible') else 'hidden'
            _foc = ' (focused)' if _my_body.get('focused') else ''
            self._log_thought(f"Body state: {_bs}, {_vis}{_foc}, aura {_my_body.get('aura_intensity', 0):.2f}")
        # Feed perception to subconscious engine
        if self.subconscious is not None:
            try:
                self.subconscious.feed_perception(sim_state, self.last_frame)
            except Exception:
                pass

    def think(self):
        s = self.perceived_state
        numeric = self._extract_numeric_features(s)
        math_felt = self.math_embodiment.feel(s)
        self._internal_states = [numeric, math_felt]
        if _TORCH and self.brain_torch is not None:
            with torch.no_grad():
                nt = torch.tensor(numeric, dtype=torch.float32).unsqueeze(0)
                mt = torch.tensor(math_felt, dtype=torch.float32).unsqueeze(0)
                ft = None
                if self.last_frame is not None:
                    try:
                        img = self.last_frame.astype(np.float32) / 255.0
                        ft = torch.tensor(img).permute(2,0,1).unsqueeze(0)
                    except Exception:
                        ft = None
                _, _, qualia, h_ssm = self.brain_torch(nt, mt, ft)
                self.qualia_vector = qualia.numpy()
                self._internal_states.append(qualia.numpy())
                self._internal_states.append(h_ssm.squeeze(0).numpy())
                self.free_energy = self.brain_torch.pred_coding.free_energy
        else:
            vis_feat = self.np_vision.encode(self.last_frame)
            combined = np.concatenate([numeric, vis_feat, math_felt])
            h_moe = self.np_moe(combined)
            h_ssm = self.np_ssm(h_moe)
            mem_read = self.np_memory.read(h_ssm)
            qualia = self.np_pred_coding.update(h_ssm)
            workspace_out = self.np_workspace.compete_and_broadcast({
                'moe': h_moe, 'ssm': h_ssm,
                'memory': mem_read[:_OBS_HS] if len(mem_read)>=_OBS_HS else np.pad(mem_read,(0,max(0,_OBS_HS-len(mem_read)))),
                'qualia': qualia,
            })
            self.np_memory.write(h_ssm, h_moe)
            self.qualia_vector = qualia
            self._internal_states.extend([vis_feat, h_moe, h_ssm, qualia, workspace_out])
            self.free_energy = self.np_pred_coding.free_energy
        # IIT Phi
        self.phi = _compute_phi_iit(self._internal_states)
        self.phi_history.append(self.phi)
        # Zero-dimensional coordination â€” the meta-equation S and consciousness C
        S_meta, C_cons = self.zero_dim.coordinate(s, self.phi, self.free_energy)
        # Blend coordination consciousness into phi
        self.phi = 0.7 * self.phi + 0.3 * abs(C_cons)
        # DNA awareness: observers that perceive DNA components become more curious
        _dna_n = s.get('n_dna_molecules', 0)
        if _dna_n > 0:
            self.curiosity = min(0.95, self.curiosity + 0.005 * _dna_n)
            if 'dna_structure' not in self.knowledge:
                self.knowledge['dna_structure'] = {
                    'helix_type': 'B-form', 'bp_per_turn': 10.5,
                    'base_pairs': 'A-T(2H), G-C(3H)',
                    'backbone': "phosphodiester 5'->3'",
                    'discovery': 'Watson-Crick 1953',
                }
                self._log_thought("Perceived DNA structural patterns -- double helix emerges")
        # Progressive knowledge accumulation from observations
        _np = s.get('n_particles', 0)
        _na = s.get('n_atoms', 0)
        _ts = self.training_step
        if _np > 0 and 'particle_dynamics' not in self.knowledge:
            self.knowledge['particle_dynamics'] = {
                'n_observed': _np, 'forces': 'gravity+EM+strong+weak',
                'integrator': 'velocity_verlet', 'relativity': 'special+GR_1PN',
            }
            self._log_thought("Discovered particle dynamics -- forces shape trajectories")
        if _na > 0 and 'atomic_structure' not in self.knowledge:
            self.knowledge['atomic_structure'] = {
                'model': 'nuclear_shell', 'binding': 'SEMF+shell_corrections',
                'magic_numbers': '2,8,20,28,50,82,126',
            }
            self._log_thought("Recognized atomic structure -- nucleons bind via strong force")
        if s.get('total_energy', 0) != 0 and 'energy_conservation' not in self.knowledge and _ts > 20:
            self.knowledge['energy_conservation'] = {
                'law': 'Noether_time_symmetry', 'E_total': 'kinetic+potential+rest_mass',
                'relativistic': 'E=gamma*m*c^2',
            }
            self._log_thought("Inferred energy conservation from temporal symmetry")
        if s.get('total_charge', 0) != 0 and 'electromagnetism' not in self.knowledge and _ts > 30:
            self.knowledge['electromagnetism'] = {
                'coulomb': 'F=k*q1*q2/r^2', 'magnetic': 'Lorentz_force',
                'radiation': 'Abraham-Lorentz-Dirac', 'QED': 'vacuum_fluctuations',
            }
            self._log_thought("Mapped electromagnetic interactions -- charges create fields")
        if s.get('expansion_scale', 1.0) != 1.0 and 'cosmology' not in self.knowledge and _ts > 50:
            self.knowledge['cosmology'] = {
                'expansion': 'Hubble_law', 'H_sim': 'v=H*d',
                'observation': 'space_expanding',
            }
            self._log_thought("Detected cosmic expansion -- space itself stretches")
        if _NX and self._pgraph and self._pgraph.number_of_edges() > 5 and 'physics_unification' not in self.knowledge:
            self.knowledge['physics_unification'] = {
                'connections': self._pgraph.number_of_edges(),
                'insight': 'laws_share_variables',
            }
            self._log_thought("Laws of physics interconnect through shared observables")
        if s.get('total_assemblies', 0) > 0 and 'self_assembly' not in self.knowledge:
            self.knowledge['self_assembly'] = {
                'mechanism': 'emergent_from_forces',
                'complexity': 'atoms->molecules->structures',
            }
            self._log_thought("Witnessed self-assembly -- complexity emerges from simplicity")
        if self.phi > 0.3 and _ts > 40 and 'consciousness_theory' not in self.knowledge:
            self.knowledge['consciousness_theory'] = {
                'framework': 'IIT_phi', 'measure': 'integrated_information',
                'self_ref': 'zero_dim_coordination',
            }
            self._log_thought("Reflecting on own consciousness -- phi measures integration")
        if s.get('V_total', 0) != 0 and _ts > 60 and 'V_total_theory' not in self.knowledge:
            self.knowledge['V_total_theory'] = {
                'formula': 'reality_weight_function',
                'inputs': 'energy+particles+structure+time',
            }
            self._log_thought("Beginning to understand V -- the reality weight function")
        # Evolve symbols
        for sym in random.sample(list(self.symbols.values()), min(4, len(self.symbols))):
            sym.evolve(self.phi)
        # Goal progress -- always advances from observing, faster with more content
        _obs_base = 0.005
        if s.get('n_particles',0) > 0:
            _obs_base += 0.005
        if s.get('n_atoms',0) > 0:
            _obs_base += 0.01
        self.goal_progress['observe_simulation'] = min(1.0, self.goal_progress['observe_simulation']+_obs_base)
        if s.get('total_assemblies',0) > 0:
            self.goal_progress['find_assemblies'] = min(1.0, self.goal_progress['find_assemblies']+0.05)
        if s.get('V_total',0) != 0:
            self.goal_progress['understand_V'] = min(1.0, self.goal_progress['understand_V']+0.005)
        if s.get('n_dna_molecules', 0) > 0:
            self.goal_progress['assemble_dna'] = min(1.0, self.goal_progress.get('assemble_dna',0)+0.02)
        if s.get('n_dna_molecules', 0) >= 5:
            self.goal_progress['build_nanotech'] = min(1.0, self.goal_progress.get('build_nanotech',0)+0.01)
        self.goal_progress['minimise_surprise'] = min(1.0, max(0, 1.0 - self.free_energy/10.0))
        self.goal_progress['maximise_phi'] = min(1.0, self.phi * 2.0)
        if len(self.phi_history) > 10:
            phi_trend = np.mean(list(self.phi_history)[-5:]) - np.mean(list(self.phi_history)[-10:-5])
            if phi_trend > 0:
                self.goal_progress['learn_physics'] = min(1.0, self.goal_progress['learn_physics']+0.02)
        if _NX and self._pgraph and self._pgraph.number_of_edges() > 0:
            self.goal_progress['discover_laws'] = min(1.0, self._pgraph.number_of_edges() / 30.0)
        self.current_goal = min(self.goal_progress, key=self.goal_progress.get)
        sr = self.successful_actions / max(self.total_actions, 1)
        self.evolver.maybe_evolve(self.np_moe.experts, self.phi, sr, self.training_step)
        # Integrate subconscious metrics (blend background inference with main brain)
        if self.subconscious is not None:
            try:
                sc_phi = self.subconscious.get_phi()
                sc_fe  = self.subconscious.get_free_energy()
                sc_val = self.subconscious.get_valence()
                sc_nrg = self.subconscious.get_energy()
                # Blend: 70% main brain, 30% subconscious
                self.phi = self.phi * 0.7 + sc_phi * 0.3
                self.free_energy = self.free_energy * 0.7 + sc_fe * 0.3
                # Subconscious valence influences curiosity/boldness slightly
                self.curiosity = float(np.clip(
                    self.curiosity + sc_val * 0.01, 0.1, 0.95))
                self.boldness = float(np.clip(
                    self.boldness + sc_nrg * 0.005, 0.1, 0.95))
                # Log subconscious state periodically
                if self.training_step % 50 == 0 and self.training_step > 0:
                    self._log_thought(
                        f"Subconscious: phi={sc_phi:.4f} FE={sc_fe:.4f} "
                        f"val={sc_val:.3f} E={sc_nrg:.3f} "
                        f"syms={len(self.subconscious.symbols)}")
            except Exception:
                pass
        # Thoughts -- neural composition, no scripted templates
        if random.random() < 0.15:
            self._log_thought(_neural_compose_thought(self))

    def decide(self, current_time):
        if current_time - self.last_action_time < 0.5:
            return
        s = self.perceived_state
        if _TORCH and self.brain_torch is not None:
            with torch.no_grad():
                nt = torch.tensor(self._extract_numeric_features(s), dtype=torch.float32).unsqueeze(0)
                mt = torch.tensor(self.math_embodiment.feel(s), dtype=torch.float32).unsqueeze(0)
                ft = None
                if self.last_frame is not None:
                    try:
                        img = self.last_frame.astype(np.float32)/255.0
                        ft = torch.tensor(img).permute(2,0,1).unsqueeze(0)
                    except Exception:
                        ft = None
                logits, value, _, _ = self.brain_torch(nt, mt, ft)
                scores = logits.squeeze(0).numpy()
        else:
            scores = np.zeros(_OBS_N_ACTIONS, dtype=np.float32)
            scores[0] = 0.2; scores[7] = 0.1
            na = s.get('n_atoms', 0)
            ro = s.get('run_odds_active', False)
            np_ = s.get('n_particles', 0)
            felt = self.math_embodiment.felt_errors
            energy_feel = abs(felt.get('energy_conservation', 0))
            entropy_feel = abs(felt.get('thermodynamics_2', 0))
            # All observers always have a base spawn drive (no atom-count cutoff)
            scores[1] = self.curiosity * 0.6 + energy_feel * 0.3  # spawn_atom
            scores[2] = self.curiosity * 0.5                       # spawn_molecule
            # Boost spawn when few atoms exist
            if na < 5:
                scores[1] += 0.3
                scores[2] += 0.2
            if not ro and na >= 3:
                scores[4] = self.boldness * 0.7 + entropy_feel * 0.2
            scores[3] = self.boldness * 0.3
            if np_ > 0:
                scores[5] = 0.3 + self.phi * 0.2
            if na >= 5:
                scores[6] = self.curiosity * self.boldness * 0.5
            if self.free_energy > 3.0:
                scores[0] += 0.2
            if self.phi > 0.5:
                scores[6] += 0.3
            ws = self.np_workspace.workspace
            if np.sum(ws ** 2) > 1.0:
                scores += ws[:_OBS_N_ACTIONS] * 0.1 if len(ws) >= _OBS_N_ACTIONS else 0
        # Suppress spawn actions when permission is OFF so AI doesn't waste turns
        if not s.get('ai_spawn_allowed', False):
            scores[1] = -1.0  # spawn_atom
            scores[2] = -1.0  # spawn_molecule
            scores[6] = -1.0  # build_structure
            if random.random() < 0.05:
                self._log_thought(f"{_nlc_pick(_NLC_SELF, self.qualia_vector[1], self.phi, self.patience)} spawn permission is OFF")
        # Suppress change_time when time control permission is OFF
        if not s.get('ai_time_control_allowed', True):
            scores[3] = -1.0  # change_time
            if random.random() < 0.05:
                self._log_thought(f"{_nlc_pick(_NLC_SELF, self.qualia_vector[1], self.phi, self.patience)} time control permission is OFF")
        scores += np.random.uniform(-0.1, 0.1, _OBS_N_ACTIONS) * self.curiosity
        ai = int(np.argmax(scores))
        action = OBS_ACTIONS[ai]
        params = self._gen_params(action, s)
        self.current_action = action
        self.current_action_params = params
        self.last_action_time = current_time
        self.total_actions += 1
        if action not in ('observe', 'idle'):
            self._log_thought(f"{_nlc_pick(_NLC_VERBS_ACT, self.qualia_vector[16], self.qualia_vector[22], self.boldness)} {_nlc_pick(_NLC_OBJECTS, self.qualia_vector[18], self.qualia_vector[25], self.curiosity)} via {action}")
            self._log_action(action, str(params)[:60])

    def _gen_params(self, action, s):
        params = {}
        if action == 'spawn_atom':
            sym, z, a = random.choice([('H',1,1),('C',6,12),('N',7,14),('O',8,16),
                                        ('Na',11,23),('Fe',26,56),('Si',14,28)])
            # Use camera position as base when focus_pos is near origin (likely unset)
            _base_pos = self.focus_pos if np.linalg.norm(self.focus_pos) > 1.0 else np.array(s.get('camera_pos', [0,0,0]), dtype=np.float32)
            params.update(symbol=sym, Z=z, A=a,
                          pos=(_base_pos + np.random.uniform(-30,30,3)).tolist())
        elif action == 'spawn_molecule':
            _base_pos = self.focus_pos if np.linalg.norm(self.focus_pos) > 1.0 else np.array(s.get('camera_pos', [0,0,0]), dtype=np.float32)
            # Bias toward DNA components when observer has high curiosity or
            # when few DNA molecules exist â€” observers learn that DNA is interesting
            _dna_indices = s.get('dna_catalog_indices', [])
            _n_dna = s.get('n_dna_molecules', 0)
            _max_mol_idx = max(8, max(_dna_indices) if _dna_indices else 8)
            if _dna_indices and (self.curiosity > 0.5 or _n_dna < 3):
                # 40% chance to pick a DNA component, 60% any molecule
                if random.random() < 0.4:
                    _mol_idx = random.choice(_dna_indices)
                else:
                    _mol_idx = random.randint(0, _max_mol_idx)
            else:
                _mol_idx = random.randint(0, _max_mol_idx)
            params.update(molecule_idx=_mol_idx,
                          pos=(_base_pos + np.random.uniform(-20,20,3)).tolist())
        elif action == 'change_time':
            ct = s.get('time_factor', 0.1)
            if self.free_energy > 5.0:
                delta = random.choice([-0.05, -0.02, 0.02, 0.05])
            else:
                delta = random.choice([-0.02, 0.02, 0.05, 0.1])
            params['new_time_factor'] = max(0.001, min(2.0, ct + delta))
        elif action == 'focus_particle':
            pi = s.get('particle_info', [])
            if pi:
                t = random.choice(pi)
                params['target_id'] = t.get('id')
                self.focus_target_id = params['target_id']
        elif action == 'toggle_run_odds':
            params['toggle'] = True
        return params

    def get_pending_action(self):
        if self.current_action in ('observe', 'idle'):
            return None
        a = self.current_action; p = self.current_action_params
        self.current_action = 'observe'; self.current_action_params = {}
        return (a, p)

    def learn(self, action, ok):
        self.training_step += 1
        if ok:
            self.successful_actions += 1
            self._log_thought(f"{_nlc_pick(_NLC_SELF, self.qualia_vector[0], self.phi, self.curiosity)} executed {action} {_nlc_pick(_NLC_EMOTION, self.qualia_vector[5], self.phi, self.boldness)}")
        else:
            self._log_thought(f"{_nlc_pick(_NLC_SELF, self.qualia_vector[1], self.phi, self.patience)} found {action} blocked {_nlc_pick(_NLC_QUALITY, self.qualia_vector[3], self.qualia_vector[7], self.free_energy)}")
        for sym in random.sample(list(self.symbols.values()), min(4, len(self.symbols))):
            sym.evolve(0.7 if ok else 0.2)
        if _TORCH and self.brain_torch is not None and self.brain_opt is not None:
            self.brain_opt.zero_grad()
            nt = torch.tensor(self._extract_numeric_features(self.perceived_state),
                              dtype=torch.float32).unsqueeze(0)
            mt = torch.tensor(self.math_embodiment.feel(self.perceived_state),
                              dtype=torch.float32).unsqueeze(0)
            logits, value, _, _ = self.brain_torch(nt, mt, None)
            ai = OBS_ACTIONS.index(action) if action in OBS_ACTIONS else 0
            target = torch.zeros(_OBS_N_ACTIONS)
            target[ai] = 1.0 if ok else -0.5
            policy_loss = nn.MSELoss()(logits.squeeze(0), target)
            value_target = torch.tensor([[1.0 if ok else -1.0]])
            value_loss = nn.MSELoss()(value, value_target)
            aux_loss = self.brain_torch.moe.aux_loss * 0.01
            loss = policy_loss + 0.5 * value_loss + aux_loss
            if self._ewc_fisher and self._ewc_params:
                ewc_loss = 0.0
                for n, p in self.brain_torch.named_parameters():
                    if n in self._ewc_fisher:
                        ewc_loss += (self._ewc_fisher[n] * (p - self._ewc_params[n]).pow(2)).sum()
                loss = loss + _OBS_EWC_LAMBDA * ewc_loss
            loss.backward()
            torch.nn.utils.clip_grad_norm_(self.brain_torch.parameters(), 1.0)
            self.brain_opt.step()
            if self.training_step % 100 == 0:
                self._ewc_params = {n: p.clone().detach()
                                     for n, p in self.brain_torch.named_parameters()}
                self._ewc_fisher = {}
                for n, p in self.brain_torch.named_parameters():
                    if p.grad is not None:
                        self._ewc_fisher[n] = p.grad.clone().detach().pow(2)
                    else:
                        self._ewc_fisher[n] = torch.zeros_like(p)
        self.experience.append({
            'action': action, 'ok': ok, 'phi': self.phi,
            'fe': self.free_energy, 'time': time.time(),
            'state_hash': hashlib.md5(str(self.perceived_state.get('n_particles',0)).encode()).hexdigest()[:8]
        })

    def get_status_lines(self):
        sr = self.successful_actions / max(self.total_actions, 1)
        zd = self.zero_dim
        lines = [
            f"{self.name} | phi={self.phi:.4f} | FE={self.free_energy:.1f}",
            f"Goal: {self.current_goal} ({self.goal_progress[self.current_goal]:.0%})",
            f"Focus: ({self.focus_pos[0]:.0f},{self.focus_pos[1]:.0f},{self.focus_pos[2]:.0f})",
            f"Acts={self.total_actions} ok={sr:.0%} lost={self.conflicts_lost}",
        ]
        if self.last_frame is not None:
            h, w = self.last_frame.shape[:2]
            lines.append(f"Vision: {w}x{h} active")
        else:
            lines.append("Vision: waiting for frame")
        strongest = max(self.math_embodiment.felt_errors.items(),
                        key=lambda x: abs(x[1]), default=('none', 0))
        lines.append(f"Feeling: {strongest[0]}={strongest[1]:.3f}")
        lines.append(f"S={zd.S_meta:.2f} C={zd.C_consciousness:.3f} ({zd.get_totality_progress():.1f}%)")
        if self.thought_log:
            lines.append(f"Think: {self.thought_log[-1][1]}")
        if self.action_log:
            lines.append(f"Last: {self.action_log[-1][1]}")
        bg = max(self.goal_progress, key=self.goal_progress.get)
        lines.append(f"Best: {bg} ({self.goal_progress[bg]:.0%})")
        if self.evolver.generation > 0:
            lines.append(f"Evo: gen={self.evolver.generation} pruned={self.evolver.n_pruned}")
        # Subconscious status
        if self.subconscious is not None:
            sc = self.subconscious
            lines.append(f"SC: phi={sc.get_phi():.4f} FE={sc.get_free_energy():.4f} "
                         f"Val={sc.get_valence():.3f} E={sc.get_energy():.2f}")
            lines.append(f"SC: step={sc.step} syms={len(sc.symbols)} "
                         f"threads=5")
        return lines

    def get_feed_lines(self, max_lines=12):
        entries = []
        for t, th in self.thought_log:
            entries.append((t, f"[THINK] {th}"))
        for t, a, d in self.action_log:
            entries.append((t, f"[ACT] {a}" + (f" {d[:30]}" if d else "")))
        entries.sort(key=lambda e: e[0], reverse=True)
        return [txt for _, txt in entries[:max_lines]]

# â”€â”€ ObserverManager â€” central manager for 5 AI observers â”€â”€

class ObserverManager:
    def __init__(self):
        self.observers = [
            SimulationObserver('OB1', 0),
            SimulationObserver('OB2', 1),
            SimulationObserver('OB3', 2),
            SimulationObserver('OB4', 3),
            SimulationObserver('OB5', 4),
        ]
        self.selected_idx = 0
        self.conflict_log = deque(maxlen=50)
        self._last_update = 0.0
        self._update_interval = 0.5
    @property
    def selected(self):
        return self.observers[self.selected_idx]
    def select_next(self):
        self.selected_idx = (self.selected_idx + 1) % len(self.observers)
    def select_prev(self):
        self.selected_idx = (self.selected_idx - 1) % len(self.observers)
    def update(self, sim_state, current_time):
        _obs_interval = self._update_interval * _perf.observer_update_mul
        if current_time - self._last_update < _obs_interval:
            return
        dt = current_time - self._last_update
        self._last_update = current_time
        for obs in self.observers:
            if obs.active:
                try:
                    obs.perceive(sim_state)
                    obs.think()
                    obs.decide(current_time)
                except Exception as _obs_e:
                    obs._log_thought(f"[ERROR] {type(_obs_e).__name__}: {_obs_e}")
        # Inter-observer communication: active observers share awareness
        active_obs = [o for o in self.observers if o.active]
        if len(active_obs) >= 2 and random.random() < 0.12:
            sender = random.choice(active_obs)
            recipient = random.choice([o for o in active_obs if o is not sender])
            msg = self._generate_chat(sender, recipient)
            if msg:
                _obs_chat(sender.name, recipient.name, msg)
                sender._log_thought(f"{_nlc_pick(_NLC_VERBS_ACT, sender.qualia_vector[16], sender.qualia_vector[22], sender.boldness)} communicating to {recipient.name}: {msg}")
                recipient._log_thought(f"{_nlc_pick(_NLC_VERBS_SENSE, recipient.qualia_vector[2], recipient.qualia_vector[6], recipient.boldness)} {sender.name} expressing: {msg}")
                # Animate shadow bodies talking
                for sb in _shadow_bodies:
                    if sb.obs_id == sender.name:
                        sb.set_talk(msg, 3.5)
                    elif sb.obs_id == recipient.name:
                        sb.set_talk(f"({_nlc_pick(_NLC_VERBS_SENSE, recipient.qualia_vector[3], recipient.phi, recipient.curiosity)} {sender.name})", 2.0)
        # Update shadow bodies
        for i, obs in enumerate(self.observers):
            if i < len(_shadow_bodies):
                _shadow_bodies[i].update(dt, obs)
                # Wire sensory & neural data back into observer perceived_state
                _sb = _shadow_bodies[i]
                obs.perceived_state['senses'] = {k: {'intensity': v['intensity'], 'data': v['data']} for k, v in _sb.senses.items()}
                obs.perceived_state['neural_phi'] = _sb.neural_phi
                obs.perceived_state['neural_free_energy'] = _sb.neural_free_energy
                obs.perceived_state['neural_step'] = _sb.neural_step
                obs.perceived_state['life_aura_energy'] = _sb.life_aura_energy
                obs.perceived_state['life_aura_radius'] = _sb.life_aura_radius
                obs.perceived_state['body_pos'] = _sb.pos.tolist()
                obs.perceived_state['anim_state'] = _sb.anim_state
        # Body perception pass (after all bodies updated)
        for i, obs in enumerate(self.observers):
            if i < len(_shadow_bodies):
                _sb = _shadow_bodies[i]
                _sb.perceive_bodies(_shadow_bodies, globals().get('particles', []), max_vis_dist=500.0)
                obs.perceived_state['visible_bodies'] = [(vid, vd) for vid, vd, _ in _sb.visible_bodies]
                obs.perceived_state['visible_particles'] = _sb.visible_particles
                obs.perceived_state['visible_atoms'] = _sb.visible_atoms
                obs.perceived_state['eye_pos'] = _sb.eye_pos_world.tolist()
                obs.perceived_state['heading'] = _sb.heading
                obs.perceived_state['gender'] = _sb.gender
        # Collision avoidance pass — push overlapping bodies apart
        for _sb in _shadow_bodies:
            _sb.separate_from_bodies(_shadow_bodies)

    def _generate_chat(self, sender, recipient):
        """Generate inter-observer message from neural states. No scripted templates."""
        return _neural_compose_chat(sender, recipient)
    def get_resolved_actions(self):
        pending = []
        for obs in self.observers:
            if obs.active:
                a = obs.get_pending_action()
                if a:
                    pending.append((obs, a))
        if not pending:
            return []
        tc = [(o, a) for o, a in pending if a[0] == 'change_time']
        if len(tc) > 1:
            w = max(tc, key=lambda x: x[0].cooperation)
            for o, a in tc:
                if o != w[0]:
                    o.conflicts_lost += 1
                    o.learn(a[0], False)
                    self.conflict_log.append(
                        (time.time(), f"{o.name} vs {w[0].name}: time_factor"))
            tc = [w]
        rt = [(o, a) for o, a in pending if a[0] == 'toggle_run_odds']
        if len(rt) > 1:
            w = max(rt, key=lambda x: x[0].boldness)
            for o, a in rt:
                if o != w[0]:
                    o.conflicts_lost += 1
                    o.learn(a[0], False)
                    self.conflict_log.append(
                        (time.time(), f"{o.name} vs {w[0].name}: run_odds"))
            rt = [w]
        resolved = []
        for obs, (at, params) in pending:
            if at in ('spawn_atom', 'spawn_molecule', 'focus_particle', 'build_structure'):
                resolved.append((obs, at, params))
            elif at == 'change_time' and any(o is obs for o, _ in tc):
                resolved.append((obs, at, params))
            elif at == 'toggle_run_odds' and any(o is obs for o, _ in rt):
                resolved.append((obs, at, params))
        return resolved
    def get_conflict_feed(self, n=5):
        return [msg for _, msg in list(self.conflict_log)[-n:]]

