def _get_sim_state_for_observers():
    """Package current simulation state for AI observer consumption.
    Includes screen capture so observers can SEE the simulation."""
    global _observer_screen_counter
    state = {
        'n_particles': len(particles),
        'n_atoms': sum(1 for p in particles if getattr(p, 'is_atom', False)),
        'simulation_time': simulation_time,
        'time_factor': time_factor,
        'V_total': V_total,
        'V_total_percent': V_total_percent,
        'total_mass': sum(p.mass for p in particles),
        'total_energy': sum(getattr(p, 'energy_kin', 0) + getattr(p, 'energy_rot', 0) for p in particles),
        'total_charge': sum(getattr(p, 'charge', 0) for p in particles),
        'total_assemblies': _self_assembly.total_assemblies,
        'total_codes': _self_assembly.total_codes,
        'run_odds_active': _self_assembly.run_odds_active,
        'n_nanotech': len(nanotech_loaded),
        'expansion_scale': expansion_scale,
        'camera_pos': camera.pos.copy() if hasattr(camera, 'pos') else np.zeros(3),
        'paused': paused,
        'ai_spawn_allowed': _ai_spawn_allowed,
        'ai_time_control_allowed': _ai_time_control_allowed,
        'ai_os_input_blocked': _ai_os_input_blocked,
        'V_subfactors': V_subfactors.copy() if V_subfactors else {},
    }
    # Particle velocities for observer feature extraction
    vels = []
    n_bonds = 0
    p_info = []
    for p in particles[:50]:
        p_info.append({'id': id(p), 'pos': p.pos.tolist(),
                       'type': getattr(p, 'base_type', 'unknown'),
                       'mass': p.mass, 'is_atom': getattr(p, 'is_atom', False),
                       'Z': getattr(p, 'Z', 0)})
        v = getattr(p, 'vel', None)
        if v is not None:
            vels.append(float(np.linalg.norm(v)))
        n_bonds += len(getattr(p, 'bonds', []))
    state['particle_info'] = p_info
    state['particle_velocities'] = vels
    state['n_bonds'] = n_bonds
    # Observer awareness: each observer can see where others are and what they're doing
    if _observer_mgr is not None:
        obs_awareness = []
        for _oa in _observer_mgr.observers:
            obs_awareness.append({
                'name': _oa.name, 'active': _oa.active,
                'focus_pos': _oa.focus_pos.tolist(),
                'goal': _oa.current_goal,
                'action': _oa.current_action,
                'phi': _oa.phi,
            })
        state['observer_peers'] = obs_awareness
    # Shadow body state for full body awareness
    if _shadow_bodies:
        state['shadow_positions'] = {sb.obs_id: sb.pos.tolist() for sb in _shadow_bodies}
        state['shadow_body_state'] = {
            sb.obs_id: {
                'pos': sb.pos.tolist(),
                'anim_state': sb.anim_state,
                'aura_intensity': sb.aura_intensity,
                'talk_bubble': sb.talk_bubble if sb.talk_timer > 0 else '',
                'teleport_alpha': sb.teleport_alpha,
                'visible': _shadow_bodies_visible,
                'focused': (_shadow_focus_idx >= 0 and _shadow_bodies[_shadow_focus_idx] is sb),
                'gender': sb.gender,
                'overall_pleasure': sb.overall_pleasure,
                'overall_arousal': sb.overall_arousal,
                'active_touch_zones': {zn: {'stimulus': zv['stimulus'], 'pleasure': zv['pleasure'],
                                            'sensitivity': zv['sensitivity']}
                                       for zn, zv in sb.tactile_zones.items() if zv['stimulus'] > 0.02},
                'recent_contacts': [(oid, z, round(i, 2)) for oid, z, i, ts in sb.touch_contacts[-5:]],
            } for sb in _shadow_bodies
        }
    # DNA / nucleic acid knowledge reference for observers
    state['dna_knowledge'] = DNA_KNOWLEDGE
    state['dna_nanotech'] = DNA_NANOTECH_INSTRUMENTS
    state['dna_catalog_indices'] = list(_DNA_CATALOG_INDICES)
    _dna_mol_count = 0
    for _sm_grp in _spawned_molecules:
        if _sm_grp and hasattr(_sm_grp[0], 'spawned_by'):
            _dna_mol_count += 1
    state['n_dna_molecules'] = _dna_mol_count
    # Music spectrum analysis data for observers
    state['music_math'] = MUSIC_MATH
    state['spectrum'] = _music_spectrum.get_summary()
    # Sensory vision: spatial environment awareness per observer
    state['active_toggles'] = {
        'grid': toggle_grid, 'em_field': toggle_em_field,
        'wave_field': toggle_wave_field, 'grav_potential': toggle_grav_potential,
        'kinetic_field': toggle_kinetic_field, 'mandelbrot_grid': toggle_mandelbrot_grid,
        'bond_lines': toggle_bond_lines, 'orbital_paths': toggle_orbital_paths,
        'radiation': toggle_radiation_density,
    }
    # Nearby particle spatial map for each shadow body
    if _shadow_bodies:
        _spatial_maps = {}
        for _sb in _shadow_bodies:
            if not np.all(np.isfinite(_sb.pos)):
                continue
            _nearby = []
            for _sp in particles[:200]:
                _sd = float(np.linalg.norm(_sp.pos - _sb.pos))
                if _sd < 500.0 and math.isfinite(_sd):
                    _nearby.append({
                        'type': getattr(_sp, 'base_type', 'unknown'),
                        'dist': round(_sd, 1),
                        'is_atom': getattr(_sp, 'is_atom', False),
                        'Z': getattr(_sp, 'Z', 0),
                        'charge': getattr(_sp, 'charge', 0),
                    })
            _spatial_maps[_sb.obs_id] = _nearby[:30]
        state['spatial_awareness'] = _spatial_maps
    # Live code awareness: current source file modification time
    try:
        import os as _os_sens
        _src_path = _os_sens.path.abspath(__file__)
        _src_mtime = _os_sens.path.getmtime(_src_path)
        state['source_file'] = _src_path
        state['source_mtime'] = _src_mtime
        state['source_size'] = _os_sens.path.getsize(_src_path)
    except Exception:
        pass
    # Camera awareness for spatial context
    state['camera_zoom'] = camera.zoom
    state['camera_rot'] = camera.rot.tolist() if hasattr(camera, 'rot') else [0, 0, 0]
    state['selected_particle_type'] = getattr(selected_particle, 'type', None) if selected_particle else None
    # Screen capture â€" every 5th call to avoid framebuffer overhead
    _observer_screen_counter += 1
    if _observer_screen_counter % 5 == 0:
        try:
            state['screen_frame'] = capture_screen(WIDTH, HEIGHT, downsample=8)
        except Exception:
            state['screen_frame'] = None
    else:
        state['screen_frame'] = None
    return state

def _create_atom_at_pos(z, pos):
    """Shared atom creation — SINGLE code path for J key, sphere nav, AI spawn, and molecules.
    Identical rendering and behavior regardless of who triggers it.
    Returns the new Atom (already appended to global particles list)."""
    data = atom_data[z]
    sym = data['symbol']
    A = round(data['atomic_weight'])
    N = A - z
    sub = []
    for _ in range(z):
        sub.append(Particle('proton', pos=pos.copy()))
    for _ in range(N):
        sub.append(Particle('neutron', pos=pos.copy()))
    for _ in range(z):
        sub.append(Particle('electron', pos=pos.copy()))
    new_atom = Atom(sym, A, sub, pos.copy())
    particles.append(new_atom)
    return new_atom

def _execute_observer_action(obs, action_type, params):
    """Execute a resolved observer action on the simulation."""
    global time_factor, _obs_last_spawn_time
    # SAFETY: Prevent AI from triggering program exit or destructive actions
    _BLOCKED_AI_ACTIONS = {"exit", "close", "quit", "shutdown", "escape", "esc_y"}
    if action_type in _BLOCKED_AI_ACTIONS:
        _obs_activity_log.append((time.time(), obs.name, action_type, "BLOCKED: forbidden action", False))
        obs.learn(action_type, False)
        return
    ok = False
    _now = time.time()
    # Gate spawn/load actions behind user permission toggle
    _SPAWN_ACTIONS = {'spawn_atom', 'spawn_molecule', 'build_structure'}
    if action_type in _SPAWN_ACTIONS and not _ai_spawn_allowed:
        _obs_activity_log.append((_now, obs.name, action_type, 'BLOCKED: AI spawn permission OFF', False))
        obs.learn(action_type, False)
        return
    if action_type == 'spawn_atom':
        z = params.get('Z', 1)
        if z not in atom_data:
            z = 1  # Default to Hydrogen if invalid Z
        pos = np.array(params.get('pos', [0, 0, 0]), dtype=float)
        # Sanitize position: NaN/Inf falls back to camera.pos (prevents invisible atoms)
        if not np.all(np.isfinite(pos)):
            pos = camera.pos.copy()
        # Constrain spawn position to near camera (within 200 units)
        cam_dist = np.linalg.norm(pos - camera.pos)
        if cam_dist > 200.0:
            pos = camera.pos + (pos - camera.pos) / max(cam_dist, 1e-6) * 200.0 * random.uniform(0.3, 1.0)
        # Use shared atom creation — identical to J key / sphere nav placement
        new_atom = _create_atom_at_pos(z, pos)
        new_atom.spawned_by = obs.name
        _obs_last_spawn_time = _now
        ok = True
    elif action_type == 'spawn_molecule':
        idx = params.get('molecule_idx', 0)
        pos = np.array(params.get('pos', [0, 0, 0]), dtype=float)
        # Sanitize position: NaN/Inf falls back to camera.pos (prevents invisible molecules)
        if not np.all(np.isfinite(pos)):
            pos = camera.pos.copy()
        # Constrain spawn position to near camera
        cam_dist = np.linalg.norm(pos - camera.pos)
        if cam_dist > 200.0:
            pos = camera.pos + (pos - camera.pos) / max(cam_dist, 1e-6) * 200.0 * random.uniform(0.3, 1.0)
        if 0 <= idx < len(molecules_catalog):
            spawn_molecule(molecules_catalog[idx], pos, spawned_by=obs.name)
            _obs_last_spawn_time = _now
            ok = True
    elif action_type == 'change_time':
        if not _ai_time_control_allowed:
            _obs_activity_log.append((_now, obs.name, action_type, 'BLOCKED: AI time control permission OFF', False))
            obs.learn(action_type, False)
            return
        new_tf = params.get('new_time_factor', time_factor)
        time_factor = max(0.001, min(2.0, new_tf))
        ok = True
    elif action_type == 'toggle_run_odds':
        _self_assembly.toggle_run_odds(simulation_time, particle_list=particles)
        ok = True
    elif action_type == 'focus_particle':
        obs.focus_target_id = params.get('target_id')
        ok = True
    elif action_type == 'toggle_loadin':
        li_key = params.get('key', '')
        if li_key in _ai_loadins:
            _toggle_loadin(li_key, source=obs.name)
            ok = True
    elif action_type == 'launch_gna':
        if not _gna_allowed:
            _obs_activity_log.append((_now, obs.name, action_type, 'BLOCKED: GNA AI permission OFF', False))
            obs.learn(action_type, False)
            return
        if not _gna_running:
            _launch_gna()
            ok = True
    elif action_type == 'stop_gna':
        if _gna_running:
            _stop_gna()
            ok = True
    # Log to activity log
    detail = str(params)[:60] if params else ''
    _obs_activity_log.append((_now, obs.name, action_type, detail if ok else f'BLOCKED: {detail}', ok))
    obs.learn(action_type, ok)
    if ok:
        _history_log.append((simulation_time, f"[AI] {obs.name}: {action_type}"))
        if len(_history_log) > _history_max:
            _history_log.pop(0)

