                                f' <button class="btn btn-sm btn-outline-success me-1 view-screen-btn" data-peer-id="{p["id"]}">View Screen</button>'
                                f' <button class="btn btn-sm btn-outline-warning call-btn" data-peer-id="{p["id"]}">Call this PC</button>'
