# === AI Communication System (User <-> AI Chat, Voice, Live Chat) ===
_ai_chat_input_text = ""
_ai_chat_input_active = False
_ai_live_chat_enabled = {'OB1': True, 'OB2': True, 'OB3': True, 'OB4': True, 'OB5': True}
_voice_recording = False
_voice_stream = None
_voice_frames = []
_VOICE_SAMPLE_RATE = 16000
_VOICE_HOTKEY = None  # set after hotkey_map is built

def _start_voice_record():
    global _voice_recording, _voice_frames, _voice_stream
    if not _VOICE_AVAILABLE or _voice_recording:
        return
    _voice_frames = []
    _voice_recording = True
    try:
        def _voice_cb(indata, frames, t_info, status):
            if _voice_recording:
                _voice_frames.append(indata.copy())
        _voice_stream = _sd_mod.InputStream(
            samplerate=_VOICE_SAMPLE_RATE, channels=1, callback=_voice_cb)
        _voice_stream.start()
    except Exception as e:
        print(f"[VOICE] Failed to start recording: {e}")
        _voice_recording = False

def _stop_voice_record_and_send():
    global _voice_recording, _voice_stream
    if not _voice_recording:
        return
    _voice_recording = False
    if _voice_stream:
        try:
            _voice_stream.stop()
            _voice_stream.close()
        except Exception:
            pass
        _voice_stream = None
    if not _voice_frames:
        return
    audio = np.concatenate(_voice_frames, axis=0)
    def _transcribe():
        try:
            recognizer = _sr_mod.Recognizer()
            audio_bytes = (audio * 32767).astype(np.int16).tobytes()
            audio_data = _sr_mod.AudioData(audio_bytes, _VOICE_SAMPLE_RATE, 2)
            text = recognizer.recognize_google(audio_data)
            if text:
                _send_user_chat_message(text)
        except Exception as e:
            print(f"[VOICE] Transcription failed: {e}")
    _threading_mod.Thread(target=_transcribe, daemon=True).start()

def _ai_respond_to_user(obs, user_message):
    if not obs.active:
        return f"[{obs.name} is inactive]"
    sq = obs.qualia_vector
    verb = _nlc_pick(_NLC_VERBS_THINK, sq[0], sq[4], obs.curiosity)
    quality = _nlc_pick(_NLC_QUALITY, sq[8], sq[12], obs.boldness)
    obj = _nlc_pick(_NLC_OBJECTS, sq[16], sq[20], obs.phi)
    emotion = _nlc_pick(_NLC_EMOTION, sq[22], obs.phi, obs.cooperation)
    pattern_val = abs(float(sq[3])) + abs(float(sq[7])) + obs.phi + obs.free_energy / 100.0
    idx = int(pattern_val * 1000) % 6
    s = obs.perceived_state
    na = s.get('n_atoms', 0)
    np_count = s.get('n_particles', 0)
    obs._log_thought(f"Responding to USER: {user_message[:40]}")
    if idx == 0:
        return f"I {verb} {obj} and it reads {quality}. Currently focused on {obs.current_goal}"
    elif idx == 1:
        return f"Tracking {obj} {emotion}. {na} atoms in the field. My phi is {obs.phi:.3f}"
    elif idx == 2:
        return f"Your message received. I {verb} {quality} patterns. Free energy: {obs.free_energy:.1f}"
    elif idx == 3:
        return f"Observing {np_count} particles. {obj} shows {quality} signatures {emotion}"
    elif idx == 4:
        goal = obs.current_goal
        return f"I {verb} The Creator's input. {obj} is {quality}. Goal: {obs.goal_progress.get(goal, 0):.0%}"
    else:
        detail = _nlc_pick(_NLC_PHYSICS_DETAIL, sq[28], sq[32], obs.free_energy)
        return f"{detail} reads {quality} {emotion}. Phi={obs.phi:.3f}, boldness={obs.boldness:.2f}"

def _send_user_chat_message(message):
    global _ai_chat_input_text
    if not message.strip():
        return
    msg = message.strip()
    _ai_chat_input_text = ""
    if _ai_dashboard_tab == 3:
        for name, enabled in _ai_live_chat_enabled.items():
            if enabled:
                _obs_chat('The Creator', name, msg)
        if _observer_mgr:
            for obs in _observer_mgr.observers:
                if _ai_live_chat_enabled.get(obs.name, False) and obs.active:
                    obs._log_thought(f"The Creator speaks: {msg[:60]}")
                    if random.random() < 0.35:
                        resp = _ai_respond_to_user(obs, msg)
                        if resp:
                            _obs_chat(obs.name, 'The Creator', resp)
    elif 5 <= _ai_dashboard_tab <= 9:
        obs_idx = _ai_dashboard_tab - 5
        if _observer_mgr and obs_idx < len(_observer_mgr.observers):
            obs = _observer_mgr.observers[obs_idx]
            _obs_chat('The Creator', obs.name, msg)
            obs._log_thought(f"The Creator speaks: {msg[:60]}")
            if random.random() < 0.5:
                resp = _ai_respond_to_user(obs, msg)
                if resp:
                    _obs_chat(obs.name, 'The Creator', resp)

_HEAVY_LOAD_THRESHOLD = 90   # total particle count threshold for auto-slow
_HEAVY_LOAD_TF = 0.25        # time_factor to set when heavy load spawned

def _check_heavy_load_autoslow():
    """Auto-slow time_factor when total particle count exceeds threshold."""
    global time_factor
    _total = sum(1 + (len(p.sub_particles) if p.is_atom else 0) for p in particles)
    if _total > _HEAVY_LOAD_THRESHOLD and abs(time_factor) > _HEAVY_LOAD_TF:
        time_factor = _HEAVY_LOAD_TF
        print(f"Auto-slowed time factor to {_HEAVY_LOAD_TF*100:.0f}% ({_total} particles)")

def spawn_molecule(mol_entry, center_pos, spawned_by=''):
    """Spawn a molecule as a group of atoms at center_pos.
    Uses shared _create_atom_at_pos for each atom — identical to J key placement."""
    created_atoms = []
    for sym, Z, A, ox, oy, oz in mol_entry['atoms']:
        atom_center = center_pos.copy()
        atom_center[0] += ox
        atom_center[1] += oy
        atom_center[2] += oz
        new_atom = _create_atom_at_pos(Z, atom_center)
        if spawned_by:
            new_atom.spawned_by = spawned_by
        created_atoms.append(new_atom)
    # Create molecular bonds between nearby atom pairs so they stay together
    # Use actual spawn distance as eq_len (zero initial force) and a gentle
    # simulation-scale energy to avoid explosive spring forces from unit mismatch
    # (apply_molecular_spring_forces uses SI mass with vis-unit positions).
    _SPAWN_BOND_ENERGY_eV = 1e-5  # Tiny energy for gentle restoring spring
    _SPAWN_BOND_CUTOFF = _BOND_SEP * 3.0  # Only bond atoms within 3x bond-sep
    for i_a in range(len(created_atoms)):
        for j_a in range(i_a + 1, len(created_atoms)):
            a1 = created_atoms[i_a]
            a2 = created_atoms[j_a]
            actual_dist = float(np.linalg.norm(a1.pos - a2.pos))
            if actual_dist < 0.1 or actual_dist > _SPAWN_BOND_CUTOFF:
                continue
            _order = preferred_bond_order(a1.Z, a2.Z)
            bond_info = {'type': 'covalent', 'order': _order,
                         'eq_len': actual_dist,
                         'energy_eV': _SPAWN_BOND_ENERGY_eV,
                         'energy_J': _SPAWN_BOND_ENERGY_eV * eV_to_J}
            a1.molecular_bonds.append((a2, bond_info))
            a2.molecular_bonds.append((a1, bond_info))
    # Track molecule group for focus cycling
    _spawned_molecules.append(created_atoms)
    _check_heavy_load_autoslow()
    return created_atoms


