    # --- Particle-type selection list (M key) ---
    if show_ptype_list and ptype_labels:
        _px = particle_list_x
        _py = particle_list_y
        _pw = particle_list_width
        _ph = particle_list_height
        Rectangle(_px, _py, _pw, _ph, color=_TH_PANEL[:3]).draw()
        Label('[M] Select Particle Type', x=_px + 8, y=_py + _ph + 4,
              font_size=10, color=_TH_TEXT_ACC).draw()
        total_items = len(ptype_labels)
        visible_lines = max(1, int(_ph / _line_h))
        max_scroll = max(0, total_items - visible_lines)
        if max_scroll > 0:
            thumb_height = max(16, _ph * visible_lines / total_items)
            thumb_y = _py + (ptype_list_offset / max_scroll) * (_ph - thumb_height) if max_scroll > 0 else _py
            Rectangle(_px + _pw - 8, int(thumb_y), 8, int(thumb_height), color=_TH_SCROLL[:3]).draw()
        vis = min(visible_lines, total_items)
        for j in range(vis):
            i = ptype_list_offset + j
            if i >= total_items:
                break
            lbl = ptype_labels[i]
