    # --- Atom-type selection list (J key) ---
    if show_atype_list and atype_labels:
        _ax = particle_list_x
        _ay = particle_list_y
        _aw = particle_list_width
        _ah = particle_list_height
        Rectangle(_ax, _ay, _aw, _ah, color=_TH_PANEL[:3]).draw()
        Label('[J] Select Atom Type', x=_ax + 8, y=_ay + _ah + 4,
              font_size=10, color=_TH_TEXT_ACC).draw()
        total_items = len(atype_labels)
        visible_lines = max(1, int(_ah / _line_h))
