        _ot_max = max(float(np.max(_music_spectrum.overtone_strengths)), 1e-10)
        for _oi in range(min(8, len(_music_spectrum.overtone_strengths))):
            _ot_val = _music_spectrum.overtone_strengths[_oi] / _ot_max
            _ot_bw = max(1, int(60 * _ot_val))
            _ot_by = _ot_y + _oi * 5
            _ot_brightness = max(40, int(200 * _ot_val))
