# Intercept window close to show exit confirmation
@window.event
def on_close():
    global show_exit_confirm
    show_exit_confirm = True
    return pyglet.event.EVENT_HANDLED  # Prevent immediate close


import wave as _wave_mod
import io as _io_mod
import tempfile as _tempfile_mod

def _generate_physics_audio(particles_snap, sim_time, channels, master_vol):
    """Generate a WAV buffer from current simulation physics state.
    Each channel maps a real physical quantity to audible sound.
    Research-grade: 44.1kHz, Planck spectrum CMB, Weizsacker binding,
    Bohr orbital harmonics, quantum interference beating, decay clicks."""
    _sr = 44100  # CD-quality sample rate
    _dur = 8.0   # loop duration in seconds
    _n = int(_sr * _dur)
    _t = np.linspace(0, _dur, _n, dtype=np.float64)
    _signal = np.zeros(_n, dtype=np.float64)

    # --- CMB Radiation: Planck blackbody spectrum at T=2.725K ---
    # B(f,T) = (2hf^3/c^2) / (exp(hf/kT) - 1)
    # Wien peak: f_peak = 2.821 * kT/h = 160.2 GHz for 2.725K
    # Map Planck spectral shape to audible octave bands (20-20kHz)
    if channels.get('cmb', {}).get('enabled', False):
        _vol = channels['cmb']['volume']
        _T_cmb = 2.725  # Kelvin
        _cmb = np.zeros(_n, dtype=np.float64)
        # Generate noise shaped by Planck spectrum mapped to audio
        # Map real freq bands logarithmically to audio: 160GHz peak -> ~800Hz audio
        for _oct in range(10):
            _f_audio = 25.0 * (2 ** _oct)  # 25, 50, 100, 200, 400, 800, 1600, 3200, 6400, 12800
            if _f_audio > _sr / 2:
                break
            # Map audio frequency to equivalent CMB frequency for Planck weight
            # Audio 800Hz -> CMB peak 160GHz; scaling factor = 2e8
            _f_cmb = _f_audio * 2e8
            # Planck spectral radiance (relative, dimensionless weight)
            _x_planck = h * _f_cmb / (k_B * _T_cmb + 1e-30)
            if _x_planck < 500:  # avoid overflow in exp
                _planck_weight = (_x_planck ** 3) / (math.exp(_x_planck) - 1.0 + 1e-30)
            else:
                _planck_weight = 0.0
            _planck_weight = min(_planck_weight, 10.0)
            # Band-limited noise at this octave, weighted by Planck spectrum
            _band_noise = np.random.normal(0, 1.0, _n)
            _kernel_sz = max(2, int(_sr / max(_f_audio, 1) / 2))
            _band_noise = np.convolve(_band_noise, np.ones(_kernel_sz) / _kernel_sz, mode='same')
            _cmb += _band_noise * _planck_weight * 0.02
        # Slow cosmic drift modulation (anisotropy fluctuations ~1e-5 amplitude)
        _cmb *= 1.0 + 0.2 * np.sin(2 * np.pi * 0.03 * _t + sim_time * 0.1)
        _signal += _cmb * _vol

    # --- Nuclear Binding Energy: Weizsacker semi-empirical mass formula ---
    # B(Z,A) = a_v*A - a_s*A^(2/3) - a_c*Z(Z-1)/A^(1/3) - a_a*(A-2Z)^2/A + delta
    # a_v=15.56, a_s=17.23, a_c=0.697, a_a=23.285 MeV (CODATA/Krane values)
    if channels.get('binding', {}).get('enabled', False):
        _vol = channels['binding']['volume']
        _total_binding_MeV = 0.0
        _n_atoms = 0
        _max_A = 1
        for p in particles_snap:
            if getattr(p, 'is_atom', False) and getattr(p, 'base_type', '') != 'decayed':
                _Z = getattr(p, 'Z', 1)
                _A = max(getattr(p, 'A', 1), 1)
                _max_A = max(_max_A, _A)
                # Weizsacker SEMF
                _bv = 15.56 * _A
                _bs = 17.23 * (_A ** (2.0 / 3.0))
                _bc = 0.697 * _Z * (_Z - 1) / (_A ** (1.0 / 3.0) + 1e-10)
                _ba = 23.285 * ((_A - 2 * _Z) ** 2) / (_A + 1e-10)
                _B = max(_bv - _bs - _bc - _ba, 0.0)
                _total_binding_MeV += _B
                _n_atoms += 1
        if _n_atoms > 0 and _total_binding_MeV > 0:
            # Map B/A (binding per nucleon) to base frequency
            # Iron-56 peak stability ~8.8 MeV/nucleon -> map to A=440Hz
            _bpa = _total_binding_MeV / max(_max_A * _n_atoms, 1)
            _base_f = 55.0 * (1.0 + _bpa / 2.0)
            _base_f = max(40.0, min(_base_f, 880.0))
            # Rich harmonic series with FM vibrato (nuclear oscillation)
            for _harm in range(1, 6):
                _amp = 0.12 / _harm
                _vibrato = 0.003 * _harm * np.sin(2 * np.pi * (0.08 * _harm + 0.02) * _t)
                _signal += _amp * _vol * np.sin(2 * np.pi * _base_f * _harm * _t + _vibrato)

    # --- Thermal Motion: Maxwell-Boltzmann distributed Brownian noise ---
    if channels.get('thermal', {}).get('enabled', False):
        _vol = channels['thermal']['volume']
        _total_ke = sum(getattr(p, 'energy_kin', 0) for p in particles_snap)
        # Effective temperature: T_eff = 2*KE/(3*N*k_B) for N particles
        _n_massive = max(sum(1 for p in particles_snap if getattr(p, 'mass', 0) > 0), 1)
        _T_eff = 2 * _total_ke / (3 * _n_massive * k_B + 1e-30)
        _T_eff = min(_T_eff, 1e12)  # cap
        # Bandwidth scales with sqrt(T) (Maxwell speed distribution width)
        _bw = min(16000, max(80, 50 * math.sqrt(max(_T_eff, 1.0) / 300.0)))
        _thermal = np.random.normal(0, 0.15, _n)
        _k_sz = max(2, int(_sr / _bw))
        _thermal = np.convolve(_thermal, np.ones(_k_sz) / _k_sz, mode='same')
        # Amplitude modulation: thermal fluctuations (chi-squared envelope)
        _fluct = np.abs(np.random.normal(1.0, 0.3, _n // 4410))
        _fluct = np.repeat(_fluct, 4410)[:_n]
        _thermal *= _fluct
        _signal += _thermal * _vol

    # --- Electron Orbital Harmonics: Bohr model frequencies ---
    # f_orbital = Z^2 * R_inf * c / n^3 where R_inf = 1.0973731568e7 m^-1
    # Map to audible range: divide by large factor to bring GHz -> Hz
    if channels.get('orbital', {}).get('enabled', False):
        _vol = channels['orbital']['volume']
        _R_inf = 1.0973731568e7  # Rydberg constant (m^-1)
        _atom_count = 0
        for p in particles_snap:
            if getattr(p, 'is_atom', False) and getattr(p, 'base_type', '') != 'decayed':
                _Z = max(getattr(p, 'Z', 1), 1)
                # Real Bohr frequency: f = Z^2 * R_inf * c / n^3
                # This is ~3.29e15 Hz for hydrogen n=1; map to audible via log scaling
                _n_shells = min(_Z, 7)  # cap shells to prevent too many tones
                for _shell in range(1, _n_shells + 1):
                    # Transition frequency n -> n+1: f ~ Z^2 * R_inf * c * (1/n^2 - 1/(n+1)^2)
                    _delta_f = _Z ** 2 * _R_inf * c * (1.0 / _shell ** 2 - 1.0 / (_shell + 1) ** 2)
                    # Map to audible: take log ratio relative to hydrogen Lyman-alpha
                    # H Lyman-alpha = 2.47e15 Hz; map this to 440Hz
                    _audio_f = 440.0 * _delta_f / (2.47e15 + 1e-10)
                    _audio_f = max(30, min(_audio_f, 8000))
                    _amp = 0.025 / _shell
                    # Slight detuning for natural sound (fine structure splitting)
                    _detune = 1.0 + 0.001 * random.gauss(0, 1)
                    _signal += _amp * _vol * np.sin(2 * np.pi * _audio_f * _detune * _t)
                _atom_count += 1
                if _atom_count >= 3:
                    break  # limit to 3 atoms to avoid cacophony

    # --- Interactions / Collisions: scattering event clicks ---
    if channels.get('collision', {}).get('enabled', False):
        _vol = channels['collision']['volume']
        _n_parts = len(particles_snap)
        _n_clicks = min(_n_parts * 2, 60)
        for _ in range(_n_clicks):
            _click_pos = random.randint(0, _n - 400)
            _click_len = random.randint(20, 120)
            _click_freq = random.uniform(600, 6000)
            _env = np.exp(-np.arange(_click_len) / (_click_len * 0.25))
            _click = _env * np.sin(2 * np.pi * _click_freq * np.arange(_click_len) / _sr)
            _signal[_click_pos:_click_pos + _click_len] += _click * _vol * 0.25

    # --- Space Expansion: Hubble parameter drone ---
    # H_0 = 67.4 km/s/Mpc = 2.18e-18 s^-1; map to deep sub-bass
    if channels.get('expansion', {}).get('enabled', False):
        _vol = channels['expansion']['volume']
        _H0_audio = 25.0  # Hubble rate mapped to ~25Hz sub-bass
        _exp_mod = 1.0 + 0.15 * np.sin(2 * np.pi * 0.02 * _t + sim_time * 0.005)
        _signal += _vol * 0.35 * np.sin(2 * np.pi * _H0_audio * _t * _exp_mod)
        _signal += _vol * 0.15 * np.sin(2 * np.pi * _H0_audio * 1.5 * _t * _exp_mod)
        _signal += _vol * 0.08 * np.sin(2 * np.pi * _H0_audio * 2.0 * _t)

    # --- Quantum Interference: beating tones from double-slit photon phases ---
    # When photons pass through both slits, their wave phases create beats
    if channels.get('quantum', {}).get('enabled', False):
        _vol = channels['quantum']['volume']
        _ds = _double_slit_exp
        if _ds.active and _ds.total_photons_detected > 5:
            # Beat frequency from slit path difference: f_beat = c*d/(lambda*L)
            _lam_vis = max(_ds.wavelength_vis, 1.0)
            _L = max(_ds.screen_dist - _ds.barrier_dist * 0.5, 1.0)
            _f_beat_raw = c * _ds.slit_sep / (_lam_vis * _L + 1e-10)
            # Map to audible: take modulo relationship
            _f_base = 220.0  # A3
            _f_beat = max(0.5, min(abs(_f_beat_raw) * 1e-13, 20.0))  # slow beating
            # Two tones close in frequency create audible beating
            _signal += _vol * 0.15 * np.sin(2 * np.pi * _f_base * _t)
            _signal += _vol * 0.15 * np.sin(2 * np.pi * (_f_base + _f_beat) * _t)
            # Fringe visibility modulates amplitude
            _V = _ds.get_fringe_visibility()
            _signal += _vol * 0.05 * _V * np.sin(2 * np.pi * _f_base * 2 * _t)
        else:
            # Quiet ambient quantum hum (vacuum fluctuations)
            _signal += _vol * 0.03 * np.sin(2 * np.pi * 136.1 * _t)  # 136.1 Hz = OM frequency

    # --- Nuclear Decay: Geiger counter clicks from radioactive events ---
    if channels.get('decay', {}).get('enabled', False):
        _vol = channels['decay']['volume']
        # Count unstable particles (those with decay_prob > 0)
        _n_unstable = sum(1 for p in particles_snap
                          if getattr(p, 'decay_prob', 0) > 0 and getattr(p, 'base_type', '') != 'decayed')
        # Poisson-distributed clicks: rate proportional to number of unstable nuclei
        _decay_rate = min(_n_unstable * 3, 80)  # clicks per 8 seconds
        for _ in range(_decay_rate):
            _dpos = random.randint(0, _n - 600)
            # Geiger counter click: sharp attack, fast exponential decay
            _dlen = random.randint(40, 200)
            _d_env = np.exp(-np.arange(_dlen) / (_dlen * 0.1))
            # Characteristic Geiger click: broadband burst with resonant peak
            _d_freq = random.uniform(2000, 8000)
            _d_click = _d_env * (0.7 * np.sin(2 * np.pi * _d_freq * np.arange(_dlen) / _sr)
                                 + 0.3 * np.random.normal(0, 1, _dlen))
            _d_click *= _d_env
            _end = min(_dpos + _dlen, _n)
            _signal[_dpos:_end] += _d_click[:_end - _dpos] * _vol * 0.4

    # --- SPECTRUM ANALYSIS: run FFT on the mixed signal before normalization ---
    global _spectrum_last_signal
    _spectrum_last_signal = _signal.copy()
    try:
        _music_spectrum.analyze(_signal)
    except Exception:
        pass

    # Crossfade for seamless loop
    _fade = int(_sr * 0.3)
    _signal[:_fade] *= np.linspace(0, 1, _fade)
    _signal[-_fade:] *= np.linspace(1, 0, _fade)
    # Normalize and convert to 16-bit PCM
    _peak = np.max(np.abs(_signal)) + 1e-10
    if _peak > 0.95:
        _signal *= 0.95 / _peak
    _signal = np.clip(_signal, -0.95, 0.95)
    _pcm = (_signal * 32000 * master_vol).astype(np.int16)
    # Write WAV at 44.1kHz
    _buf = _io_mod.BytesIO()
    with _wave_mod.open(_buf, 'wb') as _wf:
        _wf.setnchannels(1)
        _wf.setsampwidth(2)
        _wf.setframerate(_sr)
        _wf.writeframes(_pcm.tobytes())
    _buf.seek(0)
    return _buf

def _update_physics_audio():
    """Regenerate and play physics-based audio from current simulation state."""
    global _sound_player
    try:
        _buf = _generate_physics_audio(particles, simulation_time, _sound_channels, _sound_master_vol)
        _tmp = _tempfile_mod.NamedTemporaryFile(suffix='.wav', delete=False)
        _tmp.write(_buf.read())
        _tmp.close()
        _src = pyglet.media.load(_tmp.name, streaming=False)
        if _sound_player:
            try:
                _sound_player.pause()
            except Exception:
                pass
            _sound_player = None
        _sound_player = pyglet.media.Player()
        _sound_player.queue(_src)
        _sound_player.loop = True
        _sound_player.volume = _sound_master_vol
        _sound_player.play()
    except Exception as _e:
        print(f"Physics audio update failed: {_e}")

# Initial audio generation
try:
    _update_physics_audio()
except Exception as _audio_init_err:
    print(f"Physics audio init failed: {_audio_init_err}")

# Deferred SubconsciousEngine init — runs in background after window opens
def _deferred_subconscious_init():
    """Initialize heavy SubconsciousEngine instances one-by-one in background."""
    time.sleep(5.0)  # Let the window render a few frames first
    if _observer_mgr is not None:
        for i, obs in enumerate(_observer_mgr.observers):
            if not getattr(obs, '_subconscious_pending', False):
                continue
            try:
                print(f"[DeferredInit] Initializing SubconsciousEngine for {obs.name}...")
                obs._init_subconscious()
            except Exception as _e:
                print(f"[DeferredInit] {obs.name} failed: {_e}")
            time.sleep(2.0)  # Stagger to avoid CPU/memory spike
    print("[DeferredInit] All SubconsciousEngines initialized.")

threading.Thread(target=_deferred_subconscious_init, daemon=True, name="DeferredSubconscious").start()

# Schedule
pyglet.clock.schedule_interval(update, 1.0 / TARGET_FPS)

while True:
    try:
        pyglet.app.run()
        break
    except RuntimeError as _run_err:
        if 'changed size during iteration' in str(_run_err):
            print(f"[PygletRecover] {_run_err} — restarting event loop")
            continue
        raise